<script lang="ts">export let command='';export let label='';export let description='';export let copyable=true; let copied=false; const copy=async()=>{try{if(navigator?.clipboard){await navigator.clipboard.writeText(command);copied=true;setTimeout(()=>copied=false,1200);}}catch{}};</script>
<div class='cmd'><div><strong>{label}</strong><p>{description}</p></div><code>{command}</code>{#if copyable}<button on:click={copy} type='button'>{copied?'Copié':'Copier'}</button>{/if}</div>
<style>.cmd{display:grid;gap:.4rem;padding:.75rem;border:1px solid var(--border);border-radius:var(--radius-md);background:var(--surface-soft)}p{margin:.2rem 0 0;color:var(--muted)}code{overflow:auto;padding:.5rem;border-radius:8px;background:color-mix(in srgb,var(--bg) 80%, transparent)}button{justify-self:start;border:1px solid var(--border);background:var(--surface);padding:.35rem .6rem;border-radius:8px;color:var(--text)}</style>
